var fromKeyValue, setSource;

fromKeyValue = require('./from-keyvalue');

setSource = require('./set-source');

module.exports = function(the) {
  var i, key, len, opt, prefix, ref, ref1, result, value;
  prefix = "--" + (the.id.toUpperCase()) + "_";
  result = {};
  ref = process.argv;
  for (i = 0, len = ref.length; i < len; i++) {
    opt = ref[i];
    if (!(opt.slice(0, prefix.length) === prefix)) {
      continue;
    }
    opt = opt.slice(prefix.length);
    if (opt.length > 0) {
      ref1 = opt.split('='), key = ref1[0], value = ref1[1];
      if (value == null) {
        value = true;
      }
      fromKeyValue(result, key, value);
    }
  }
  if (Object.keys(result).length > 0) {
    setSource(result, 'cli');
    return {
      objects: [result]
    };
  } else {
    return {
      objects: []
    };
  }
};

module.exports.scopes = ['cli', 'all', 'each'];
